-- Add Visual layer at the top of the Warm-Up happy path blueprint.

update public.layers
set row_position = row_position + 1
where path_id = 'a0000000-0000-4000-8000-000000000300';

insert into public.layers (id, path_id, name, row_position)
values (
  'a0000000-0000-4000-8000-000000000310',
  'a0000000-0000-4000-8000-000000000300',
  'Visual',
  0
)
on conflict (id) do update set
  name = excluded.name,
  row_position = excluded.row_position;

